gV8(){return"Cinimex:\u0421\u0442\u0430\u0440\u0448\u0438\u0439 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0447\u0438\u043a:\u0420\u0435\u0430\u043b\u0438\u0437\u043e\u0432\u0430\u043b \u043a\u043e\u0440\u043f\u043e\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0435 \u0445\u0440\u0430\u043d\u0438\u043b\u0438\u0449\u0435 \u043c\u043e\u0431\u0438\u043b\u044c\u043d\u044b\u0445 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0439 (Flutter + Dart + PostgreSQL) - \u0440\u0430\u0441\u043f\u043e\u0437\u043d\u0430\u0432\u0430\u043d\u0438\u0435 APK/IPA, \u0430\u0434\u043c\u0438\u043d\u043a\u0430, \u043e\u0442\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u043d\u0438\u0435 \u043e\u0431\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u0439;\u0420\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0430\u043b \u0441 \u043d\u0443\u043b\u044f \u043c\u043e\u0431\u0438\u043b\u044c\u043d\u043e\u0435 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0434\u043b\u044f \u043c\u0430\u0433\u0430\u0437\u0438\u043d\u0430 \u043c\u0435\u0440\u0447\u0430 \u043d\u0430 Flutter \u0441 CI/CD \u0447\u0435\u0440\u0435\u0437 GitLab Runner;\u0423\u0447\u0430\u0441\u0442\u0432\u043e\u0432\u0430\u043b \u0432 \u043f\u0440\u0435\u0441\u0435\u0439\u043b\u0435 \u0438 \u043f\u0440\u043e\u0435\u043a\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0438 \u0430\u0440\u0445\u0438\u0442\u0435\u043a\u0442\u0443\u0440\u044b \u0440\u0435\u0448\u0435\u043d\u0438\u0439;\u0420\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0430\u043b \u0438 \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043b \u043a\u043e\u0440\u043f\u043e\u0440\u0430\u0442\u0438\u0432\u043d\u044b\u0439 UI-kit;\u041d\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u043b CI/CD (GitLab Runner, GitHub Workflow);\u041f\u0440\u043e\u0432\u043e\u0434\u0438\u043b \u043a\u043e\u0434-\u0440\u0435\u0432\u044c\u044e, \u0441\u043e\u0431\u0435\u0441\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f, \u043c\u0435\u043d\u0442\u043e\u0440\u0438\u043d\u0433;\u0411\u044b\u043b \u043b\u0438\u0434\u0435\u0440\u043e\u043c Flutter-\u0441\u043e\u043e\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u0432\u043d\u0443\u0442\u0440\u0438 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 (\u043c\u0438\u0442\u0430\u043f\u044b, \u0432\u043d\u0435\u0434\u0440\u0435\u043d\u0438\u0435 \u043d\u043e\u0432\u044b\u0445 \u043f\u0440\u0430\u043a\u0442\u0438\u043a);\u0420\u0443\u043a\u043e\u0432\u043e\u0434\u0438\u043b \u043f\u0440\u0435\u0434\u0434\u0438\u043f\u043b\u043e\u043c\u043d\u043e\u0439 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0441\u0442\u0443\u0434\u0435\u043d\u0442\u043e\u0432 (OpenAPI/Swagger \u0434\u043b\u044f \u0444\u0440\u043e\u043d\u0442\u0435\u043d\u0434\u0430):2019-10-01"},
